UPDATE api_access SET
    status = #{status}

        ,rate_limit = #{rate_limit}


        ,rate_limit_per_min = #{rate_limit_per_min}


        ,billing_date = #{billing_date}


        ,next_billing_date = #{next_billing_date}


        ,updated_by = #{author}

WHERE


            security_key = #{security_key}


            id_user = #{employee_id}

mapper.select:
WITH RECURSIVE days AS ( SELECT 1 AS `day` UNION ALL SELECT `day` + 1 FROM days WHERE `day` < DAY(LAST_DAY(NOW())) ), data AS ( SELECT DAY(time) AS `day`, COUNT(*) AS total FROM api_usage WHERE time >= DATE_FORMAT(CURDATE(), '%Y-%m-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-%m-01'), INTERVAL 1 MONTH)
AND id_endpoint = #{id_enpoint}
AND id_user = #{employee_id}
GROUP BY DAY(time) ) SELECT DATE_FORMAT(CONCAT(YEAR(NOW()), '-', MONTH(NOW()), '-', d.`day`), '%m-%d-%Y') AS label, IFNULL(t.total, 0) AS value FROM days d LEFT JOIN data t ON t.`day` = d.`day` ORDER BY d.`day`;

WITH RECURSIVE months AS ( SELECT 1 AS `month` UNION ALL SELECT `month` + 1 FROM months WHERE `month` < 12 ), data AS ( SELECT MONTH(time) AS `month`, COUNT(*) AS total FROM api_usage WHERE time >= DATE_FORMAT(CURDATE(), '%Y-01-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-01-01'), INTERVAL 1 YEAR)
AND id_endpoint = #{id_enpoint}
AND id_user = #{employee_id}
GROUP BY MONTH(time) ) SELECT DATE_FORMAT(CONCAT(YEAR(NOW()), '-', m.`month`, '-01'), '%b-%Y') AS label, IFNULL(d.total, 0) AS value FROM months m LEFT JOIN data d ON d.`month` = m.`month` ORDER BY m.`month`;

WITH quarters AS ( SELECT 1 AS q UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4 ), data AS ( SELECT QUARTER(time) AS q, COUNT(*) AS total FROM api_usage WHERE time >= DATE_FORMAT(CURDATE(), '%Y-01-01') AND time < DATE_ADD(DATE_FORMAT(CURDATE(), '%Y-01-01'), INTERVAL 1 YEAR)
AND id_endpoint = #{id_enpoint}
AND id_user = #{employee_id}
GROUP BY QUARTER(time) ) SELECT CONCAT('Q', q.q, '-', YEAR(NOW())) AS label, IFNULL(d.total, 0) AS value FROM quarters q LEFT JOIN data d ON d.q = q.q ORDER BY q.q;

WITH RECURSIVE years AS (
    SELECT COALESCE(MIN(YEAR(time)), YEAR(NOW())) AS y FROM api_usage WHERE id_user = #{employee_id}
    UNION ALL
    SELECT y + 1 FROM years WHERE y < YEAR(NOW())
),
data AS (
    SELECT
        YEAR(time) AS y,
        COUNT(*) AS total
    FROM api_usage


            WHERE id_user = #{employee_id}

                AND id_endpoint = #{id_enpoint}





    GROUP BY YEAR(time)
)
SELECT
    CONCAT(years.y, '') AS label,
    IFNULL(d.total, 0) AS value
FROM years
LEFT JOIN data d ON d.y = years.y
ORDER BY years.y;

mapper.update:
UPDATE api_access SET
    updated_date = now(),
    security_key = SHA1(#{security_key_str}),
    security_key_name = #{security_key_name}
WHERE id_user = #{employee_id}

mapper.select:
SELECT count(au.id_endpoint) FROM api_usage au INNER JOIN api_usage au ON ac.id_user = au.id_user WHERE ac.security_key = #{security_key} AND status = 1
AND au.time >= NOW() - INTERVAL 1 MINUTE;
AND au.time >= DATE(IFNULL(ac.billing_date, NOW())) AND au.time < DATE(DATE_ADD(IFNULL(ac.billing_date, NOW()), INTERVAL 1 MONTH));

SELECT CONCAT(e.first_name, ' ', e.last_name) as full_name, e.email, c.`name` as company_name, ac.id_user, CASE WHEN ac.status = 0 THEN 'INACTIVE' WHEN ac.status = 1 THEN IF(ac.next_billing_date < NOW(),'UNPAID','ACTIVE') WHEN ac.status = 2 THEN 'LOCK' END AS status, CASE WHEN count(au.id_endpoint) = 0 OR ac.updated_date IS NULL THEN 'Never Used' ELSE DATE_FORMAT(ac.updated_date, '%M %e, %Y – %l:%i %p') END as last_api_call, IFNULL(ac.updated_by, 'System') as active_by, count(au.id_endpoint) as total_usage, IF(ac.rate_limit = 0, 0, (count(id_endpoint) / ac.rate_limit * 100)) as usage_percent, ac.rate_limit FROM api_access ac INNER JOIN employee e on e.id = ac.id_user INNER JOIN company c on c.id = e.id_company LEFT JOIN api_usage au on au.id_user = ac.id_user WHERE e.`status` = 1 AND e.is_delete = 0 AND c.`status` = 1 AND c.is_delete = 0
AND ( e.last_name LIKE CONCAT('%', #{keyword}, '%') OR e.first_name LIKE CONCAT('%', #{keyword}, '%') OR e.email LIKE CONCAT('%', #{keyword}, '%') )
GROUP BY ac.id_user LIMIT ${limit} OFFSET ${offset}
